const MIN_BLUEPRINT_ZOOM=.3
const applyBlueprintZoom=(shell:HTMLDivElement,value:number)=>{
  const rasterGuard=Math.max(0,1-value)
  shell.style.transform=`scale(${value})`
  shell.style.setProperty('--blueprint-line',`${Math.max(.75,1/value+rasterGuard)}px`)
  // The dark block outline should shrink with the blueprint instead of being
  // held at a constant rendered width.  Below 55% it is omitted entirely so
  // the block texture and number retain enough room to read.
  shell.style.setProperty('--blueprint-inner-line',value<.55?'0px':'1px')
}
