  const [fishboneMode,setFishboneMode]=useState<FishboneMode>(saved.fishboneMode??'auto'),[fishboneManual,setFishboneManual]=useState<Record<string,number[]>>(saved.fishboneManual??{}),[fishbonePackColumns,setFishbonePackColumns]=useState(saved.fishbonePackColumns===true)
  const [fishboneSpatialAudio,setFishboneSpatialAudio]=useState(saved.fishboneSpatialAudio===true),[fishbonePlayerHeight,setFishbonePlayerHeight]=useState(saved.fishbonePlayerHeight??5)
  const [layerIndex,setLayerIndex]=useState(initialViewState.layerIndex),[showOptions,setShowOptions]=useState(false),[showExport,setShowExport]=useState(false),[showLegend,setShowLegend]=useState(false),[settingHelp,setSettingHelp]=useState<string|null>(null)
  const [selected,setSelected]=useState<string|null>(null),[startStep,setStartStep]=useState<number|null>(null),[playingStep,setPlayingStep]=useState(-1),[previewCell,setPreviewCell]=useState<string|null>(null),[particles,setParticles]=useState<number[]>([])
  const [zoomDisplay,setZoomDisplay]=useState(initialViewState.zoom)
  const poly=maxPolyphony(project),ja=language==='ja',eligible=kind==='easy'?poly<=3:kind==='packed'?poly<=6:true
  const locale=blueprintLocales[language]
  const t=(key:string,japanese:string,english:string)=>ja?japanese:(locale?.[key]??english)
  const repeaterCopy=ja?{setting:'リピーター',delay:'遅延数',clicks:'クリック数',delayLegend:'リピーターの向きと遅延数',clicksLegend:'リピーターの向きとクリック数',help:'リピーターに表示する数字を、遅延数と右クリック数で切り替えます。クリック数は遅延数より1小さく、白い五角形で表示を区別します。'}:(repeaterDisplayLocales[language]??repeaterDisplayLocales.en)
  const easy=useMemo(()=>poly<=3?generateEasyBlueprint(project,instruments,runLength,fold,includeSilentEdges):null,[project,instruments,runLength,fold,includeSilentEdges,poly])
  const compact=useMemo(()=>poly<=6?generateCompactBlueprint(project,instruments,compactSize,false,compactFold):null,[project,instruments,compactSize,compactFold,poly])
  const fishbone=useMemo(()=>kind==='fishbone'?generateFishboneBlueprint(project,instruments,fishboneMode,fishboneManual,fishbonePackColumns):EMPTY_FISHBONE,[kind,project,instruments,fishboneMode,fishboneManual,fishbonePackColumns])
  const plan:BlueprintPlan|null=kind==='easy'?easy:kind==='packed'?(compact?.layers[Math.min(layerIndex,(compact?.layers.length??1)-1)]??null):fishbone.plan
  const fishboneDistanceTable=useMemo(()=>createFishboneDistanceTable(fishbonePlayerHeight),[fishbonePlayerHeight])
  const fishboneMixes=useMemo(()=>{const sourceX=fishbone.plan.cells.find(item=>item.type==='source')?.x??0,map=new Map<string,{volume:number;pan:number}>();fishbone.plan.cells.forEach(item=>{if(item.type!=='note'||item.trackId===undefined||item.step===undefined||item.label===undefined)return;const offset=item.x-sourceX,distance=Math.min(FISHBONE_AUDIBLE_DISTANCE,Math.abs(offset)),mix=fishboneDistanceTable[distance];map.set(`${item.trackId}:${item.step}:${item.label}`,{volume:mix.gain,pan:Math.sign(offset)*mix.pan})});return map},[fishbone.plan,fishboneDistanceTable])
